
const loadMap = () => {
	let center = getCenter(data);
	let position = new naver.maps.LatLng(center.lat, center.lng);

	let map = new naver.maps.Map('map', {
		center: position,
		zoom: 15
	});

	let markers = [], marker;

	for (let row of data) {
		position = new naver.maps.LatLng(row.lat, row.lng);
	
		marker = new naver.maps.Marker({
			map: map,
			position: position,
		});
	};
}

const getCenter = (coordinates) => {
	let totalLat = 0;
	let totalLng = 0;
	
	// 위도와 경도의 합을 구합니다.
	coordinates.forEach(coord => {
		totalLat += coord.lat;
		totalLng += coord.lng;
	});
	
	// 평균을 계산하여 중앙 좌표를 구합니다.
	const centerLat = totalLat / coordinates.length;
	const centerLng = totalLng / coordinates.length;
	
	return { lat: centerLat, lng: centerLng };
}

document.addEventListener("DOMContentLoaded", () => {
	if (data && window.location.pathname.startsWith("/location")) {
		loadMap()
	}
});


